#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int minAddToMakeValidNaive(char *s) {
    int moves = 0;
    int len = strlen(s);
    int *stack = (int *)malloc(len * sizeof(int));
    int top = -1;

    for (int i = 0; i < len; i++) {
        if (s[i] == '(') {
            stack[++top] = s[i];
        } else {
            if (top == -1) {
                moves++;
            } else {
                top--;
            }
        }
    }

    moves += top + 1;
    free(stack);
    return moves;
}

int main() {
    int T;
    scanf("%d", &T);
    getchar();

    for (int i = 0; i < T; i++) {
        char s[1001];
        fgets(s, 1001, stdin);
        s[strcspn(s, "\n")] = 0;
        printf("%d\n", minAddToMakeValidNaive(s));
    }

    return 0;
}

