#include <iostream>
#include <stack>
#include <string>
using namespace std;

int minAddToMakeValidNaive(string s) {
    int moves = 0;
    stack<char> st;

    for (char c : s) {
        if (c == '(') {
            st.push(c);
        } else {
            if (st.empty()) {
                moves++;
            } else {
                st.pop();
            }
        }
    }

    moves += st.size();
    return moves;
}

